  {"id":"bhumiamla","name":"Bhumiamla (Chamber Bitter)","sanskrit":"\u092d\u0942\u092e\u094d\u092f\u093e\u092e\u0932\u0915\u0940","alsoKnownAs":["Tamalki"],"botanical":"Phyllanthus niruri","family":"Phyllanthaceae","partsUsed":["Whole plant"],"rasa":["Tikta","Kashaya","Madhura"],"guna":["Laghu","Ruksha"],"virya":"Sheeta","vipaka":"Madhura","dosha":"Balances Pitta & Kapha","classicalUses":["Yakrit (jaundice)","Asmari (calculi)","Pramehaghna","Krimighna"],"evidence":"Moderate","evidenceNote":"Hepatitis B and renal-stone benefits traditionally cited; trial evidence is preliminary.","formulations":["Bhumiamla Swarasa","Yakritplihari Lauha"],"source":"Bhavaprakasha Nighantu","precautions":"May lower blood sugar; caution with antidiabetics.","emoji":"\ud83c\udf3f","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/68/Phyllanthus_niruri_001.jpg/640px-Phyllanthus_niruri_001.jpg","category":"detox"},
  {"id":"chitrak","name":"Chitrak","sanskrit":"\u091a\u093f\u0924\u094d\u0930\u0915","alsoKnownAs":["Agni","Vahni"],"botanical":"Plumbago zeylanica","family":"Plumbaginaceae","partsUsed":["Root"],"rasa":["Katu"],"guna":["Laghu","Ruksha","Tikshna","Sara"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Vata; aggravates Pitta","classicalUses":["Deepana","Pachana","Arshoghna (piles)","Kusthaghna","Vata-anaha"],"evidence":"Moderate","evidenceNote":"Plumbagin shows anti-inflammatory and anticancer preclinical activity; very hot in action.","formulations":["Chitrakadi Vati","Chitrak Haritaki","Shankhapushpi Taila"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Avoid in pregnancy and active ulcers.","emoji":"\ud83d\udd25","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Plumbago_zeylanica.jpg/640px-Plumbago_zeylanica.jpg","category":"digestive"},
  {"id":"ajwain","name":"Ajwain (Carom)","sanskrit":"\u0905\u091c\u0935\u093e\u092f\u0928","alsoKnownAs":["Yavani","Deepika"],"botanical":"Trachyspermum ammi","family":"Apiaceae","partsUsed":["Seed"],"rasa":["Katu","Tikta"],"guna":["Laghu","Ruksha","Tikshna"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Kapha","classicalUses":["Anaha","Adhmana","Krimighna","Kasa-shwasahara"],"evidence":"Strong","evidenceNote":"Thymol pharmacology well-documented as antimicrobial, antispasmodic, and digestive.","formulations":["Ajamodadi Churna","Hingvashtak Churna"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Hot in action; limit in pregnancy.","emoji":"\ud83e\uded8","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Trachyspermum_ammi.jpg/640px-Trachyspermum_ammi.jpg","category":"digestive"},
  {"id":"methi","name":"Methi (Fenugreek)","sanskrit":"\u092e\u0947\u0925\u093f\u0915\u093e","alsoKnownAs":["Methini","Chandrika"],"botanical":"Trigonella foenum-graecum","family":"Fabaceae","partsUsed":["Seed","Leaf"],"rasa":["Katu","Tikta"],"guna":["Laghu","Snigdha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Kapha","classicalUses":["Pramehaghna","Stanyajanana","Deepana","Vata-shoola"],"evidence":"Strong","evidenceNote":"Galactagogue, lipid-lowering, and blood-sugar effects well-supported.","formulations":["Methi Modaka","Stanyajanana Ghritham"],"source":"Bhavaprakasha Nighantu","precautions":"May lower blood sugar; can cause maple-smell in urine/sweat.","emoji":"\ud83d\udfe2","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/48/Trigonella_foenum-graecum_seeds.jpg/640px-Trigonella_foenum-graecum_seeds.jpg","category":"digestive"},
  {"id":"saunf","name":"Saunf (Fennel)","sanskrit":"\u0936\u0924\u092a\u0941\u0937\u094d\u092a\u093e","alsoKnownAs":["Mishreya","Madhurika"],"botanical":"Foeniculum vulgare","family":"Apiaceae","partsUsed":["Seed"],"rasa":["Madhura","Katu","Tikta"],"guna":["Laghu","Snigdha"],"virya":"Sheeta","vipaka":"Madhura","dosha":"Balances Vata & Pitta","classicalUses":["Anaha","Stanyajanana","Chakshushya","Dipanapachana"],"evidence":"Moderate","evidenceNote":"Carminative and galactagogue effects well-known; phytoestrogens present.","formulations":["Saunf Arka","Mishreya Taila"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Phytoestrogens, caution in estrogen-sensitive conditions.","emoji":"\ud83c\udf31","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Foeniculum_vulgare_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-100.jpg/640px-Foeniculum_vulgare_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-100.jpg","category":"digestive"},
  {"id":"dhanyaka","name":"Dhanyaka (Coriander)","sanskrit":"\u0927\u093e\u0928\u094d\u092f\u0915","alsoKnownAs":["Kustumburu"],"botanical":"Coriandrum sativum","family":"Apiaceae","partsUsed":["Seed","Leaf"],"rasa":["Kashaya","Tikta","Madhura","Katu"],"guna":["Laghu","Snigdha"],"virya":"Ushna","vipaka":"Madhura","dosha":"Balances all three doshas","classicalUses":["Jwaraghna","Trishnanigrahana (thirst)","Mutrala","Deepana","Hridya"],"evidence":"Strong","evidenceNote":"Linalool has documented anxiolytic, digestive, and antidiabetic effects.","formulations":["Dhanyakadi Hima","Dhanyapanchak Kwatha"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Generally safe.","emoji":"\ud83c\udf3f","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/55/Coriandrum_sativum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-033.jpg/640px-Coriandrum_sativum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-033.jpg","category":"digestive"},
  {"id":"jeeraka","name":"Jeeraka (Cumin)","sanskrit":"\u091c\u0940\u0930\u0915","alsoKnownAs":["Shvetajiraka (white)","Krishnajiraka (black)"],"botanical":"Cuminum cyminum","family":"Apiaceae","partsUsed":["Seed"],"rasa":["Katu","Tikta"],"guna":["Laghu","Ruksha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Kapha","classicalUses":["Deepana","Pachana","Anaha","Stanyajanana","Jwaraghna"],"evidence":"Strong","evidenceNote":"Cuminaldehyde and thymol effects well-documented.","formulations":["Jeerakadyarishta","Sarpagandhaghan Vati"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Generally safe; may increase Pitta in excess.","emoji":"\ud83e\uded8","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/05/Cuminum_cyminum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-119.jpg/640px-Cuminum_cyminum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-119.jpg","category":"digestive"},
  {"id":"hing","name":"Hingu (Asafoetida)","sanskrit":"\u0939\u0940\u0902\u0917\u0941","alsoKnownAs":["Bahlika","Jatu"],"botanical":"Ferula assa-foetida","family":"Apiaceae","partsUsed":["Resin (Niryasa)"],"rasa":["Katu"],"guna":["Laghu","Snigdha","Tikshna","Sara"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Kapha","classicalUses":["Anaha","Adhmana","Shoola","Krimighna","Vata-anaha"],"evidence":"Strong","evidenceNote":"Antispasmodic and antiflatulent effects well-known; traditionally used for Vata abdominal pain.","formulations":["Hingvashtak Churna","Hingutriguna Taila"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Strong odor; small amounts sufficient. Not for infants.","emoji":"\ud83e\uddc4","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/Ferula_assa-foetida.jpg/640px-Ferula_assa-foetida.jpg","category":"digestive"},
  {"id":"lavang","name":"Lavanga (Clove)","sanskrit":"\u0932\u0935\u0902\u0917","alsoKnownAs":["Devakusuma"],"botanical":"Syzygium aromaticum","family":"Myrtaceae","partsUsed":["Flower bud"],"rasa":["Katu","Tikta"],"guna":["Laghu","Tikshna"],"virya":"Sheeta","vipaka":"Katu","dosha":"Balances Kapha & Pitta","classicalUses":["Danta-shoola (toothache)","Kasa-shwasahara","Chakshushya","Vata-shama"],"evidence":"Strong","evidenceNote":"Eugenol pharmacology is well-documented; dental analgesic use is supported.","formulations":["Lavangadi Vati","Avipattikar Churna"],"source":"Bhavaprakasha Nighantu","precautions":"Undiluted oil is irritating; do not exceed recommended dose.","emoji":"\ud83d\udfe4","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/41/Syzygium_aromaticum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-108.jpg/640px-Syzygium_aromaticum_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-108.jpg","category":"respiratory"},
  {"id":"ela","name":"Ela (Cardamom)","sanskrit":"\u090f\u0932\u093e","alsoKnownAs":["Sukashma","Truti"],"botanical":"Elettaria cardamomum","family":"Zingiberaceae","partsUsed":["Seed"],"rasa":["Katu","Madhura"],"guna":["Laghu","Ruksha"],"virya":"Sheeta","vipaka":"Madhura","dosha":"Tridoshic","classicalUses":["Hridya","Anaha","Kasa-shwasahara","Mukha-dourgandhya-nashaka"],"evidence":"Strong","evidenceNote":"Antispasmodic, carminative, and antioxidant effects documented.","formulations":["Eladi Vati","Eladi Ghrita","Sitopaladi Churna"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Gallstone patients, use cautiously.","emoji":"\ud83d\udc9b","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5a/Elettaria_cardamomum.jpg/640px-Elettaria_cardamomum.jpg","category":"digestive"},
  {"id":"dalchini","name":"Dalchini (Cinnamon)","sanskrit":"\u0924\u094d\u0935\u0915\u094d","alsoKnownAs":["Tamalaka","Tvak"],"botanical":"Cinnamomum verum","family":"Lauraceae","partsUsed":["Bark"],"rasa":["Katu","Madhura","Tikta"],"guna":["Laghu","Ruksha","Tikshna"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Kapha","classicalUses":["Hridya","Pramehaghna","Deepana","Kasa-shwasahara"],"evidence":"Strong","evidenceNote":"Cinnamaldehyde and procyanidins show blood-sugar and lipid benefits.","formulations":["Dalchiniyoga","Triphala (adjunct)"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"Coumarin content (esp. cassia), limit long-term high dose.","emoji":"\ud83d\udeb5","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/c3/Cinnamomum_verum.jpg/640px-Cinnamomum_verum.jpg","category":"digestive"},
  {"id":"keshar","name":"Kumkuma (Saffron)","sanskrit":"\u0915\u0941\u0902\u0915\u0941\u092e","alsoKnownAs":["Kashmiram","Kesar"],"botanical":"Crocus sativus","family":"Iridaceae","partsUsed":["Stigma"],"rasa":["Katu","Tikta"],"guna":["Snigdha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Vata & Pitta","classicalUses":["Varnakrta (complexion)","Anartava (amenorrhea)","Vedanashamaka","Hridya","Medhya"],"evidence":"Moderate","evidenceNote":"Crocin and safranal show antidepressant and neuroprotective activity; expensive, adulteration common.","formulations":["Kumkuma Taila","Kumkumadi Taila"],"source":"Charaka Samhita, Sutrasthana 27","precautions":"High dose is uterotonic, avoid in pregnancy.","emoji":"\ud83c\udf38","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Crocus_sativus_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-101.jpg/640px-Crocus_sativus_-_K%C3%B6hler%E2%80%93s_Medizinal-Pflanzen-101.jpg","category":"skin"},
