  {"id":"khadira","name":"Khadira (Catechu)","sanskrit":"\u0916\u0926\u093f\u0930","alsoKnownAs":["Gayasthah","Somavalka"],"botanical":"Acacia catechu","family":"Fabaceae","partsUsed":["Heartwood","Extract (Kath)"],"rasa":["Tikta","Kashaya"],"guna":["Laghu","Ruksha"],"virya":"Sheeta","vipaka":"Katu","dosha":"Balances Pitta & Kapha","classicalUses":["Kusthaghna","Mukha-rogahara (oral)","Atisara","Vranaropana"],"evidence":"Strong","evidenceNote":"Catechin and tannin pharmacology well-known; oral and skin uses supported.","formulations":["Khadirarishta","Khadiradi Vati","Lodhra Khadira Kwatha"],"source":"Charaka Samhita, Sutrasthana 4","precautions":"Tannins can interfere with iron absorption.","emoji":"\ud83d\udfeb","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Acacia_catechu.jpg/640px-Acacia_catechu.jpg","category":"skin"},
  {"id":"meshshringi","name":"Mesha Shrungi (Gymnema)","sanskrit":"\u092e\u0947\u0937\u0936\u0943\u0902\u0917\u0940","alsoKnownAs":["Madhunashini","Gudmar"],"botanical":"Gymnema sylvestre","family":"Asclepiadaceae","partsUsed":["Leaf"],"rasa":["Tikta","Kashaya"],"guna":["Laghu","Ruksha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Pitta","classicalUses":["Pramehaghna","Madhu-mehaghna (sweet taste destroyer)","Kusthaghna","Hridya"],"evidence":"Strong","evidenceNote":"Gymnemic acids well-documented for blood-sugar control and sugar-craving reduction.","formulations":["Madhunashini Yoga","Meshashringyadi Churna"],"source":"Bhavaprakasha Nighantu","precautions":"Potentiates antidiabetics; risk of hypoglycemia.","emoji":"\ud83c\udf6c","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/Gymnema_sylvestre.jpg/640px-Gymnema_sylvestre.jpg","category":"metabolic"},
  {"id":"karela","name":"Karela (Bitter Gourd)","sanskrit":"\u0915\u093e\u0930\u0935\u0947\u0932\u094d\u0932\u0915","alsoKnownAs":["Sushavi","Kandakataka"],"botanical":"Momordica charantia","family":"Cucurbitaceae","partsUsed":["Fruit","Leaf"],"rasa":["Tikta","Katu"],"guna":["Laghu","Ruksha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Pitta","classicalUses":["Pramehaghna","Deepana","Kusthaghna","Jwaraghna"],"evidence":"Moderate","evidenceNote":"Charantin and polypeptide-p show hypoglycemic effects; quality of evidence is mixed.","formulations":["Karelayoga","Karelaharidra Khanda"],"source":"Bhavaprakasha Nighantu","precautions":"Risk of hypoglycemia; not for G6PD deficiency; can induce early labor.","emoji":"\ud83e\udd52","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5f/Momordica_charantia.jpg/640px-Momordica_charantia.jpg","category":"metabolic"},
  {"id":"palasha","name":"Palasha (Flame of the Forest)","sanskrit":"\u092a\u0932\u093e\u0936","alsoKnownAs":["Kimshuka","Raktapushpa"],"botanical":"Butea monosperma","family":"Fabaceae","partsUsed":["Bark","Flower","Seed","Gum"],"rasa":["Kashaya","Tikta","Katu"],"guna":["Laghu","Ruksha","Sara"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Pitta","classicalUses":["Kusthaghna","Krimighna","Mutrala","Sandhana (fracture healing)"],"evidence":"Moderate","evidenceNote":"Anti-inflammatory, antimicrobial, and wound-healing effects documented.","formulations":["Palashabhasma","Kustharaksha Taila"],"source":"Charaka Samhita, Sutrasthana 4","precautions":"Hot, use in moderation.","emoji":"\ud83d\udd25","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Butea_monosperma.jpg/640px-Butea_monosperma.jpg","category":"skin"},
  {"id":"saptaparna","name":"Saptaparna (Alstonia)","sanskrit":"\u0938\u092a\u094d\u0924\u092a\u0930\u094d\u0923","alsoKnownAs":["Saptachhada"],"botanical":"Alstonia scholaris","family":"Apocynaceae","partsUsed":["Bark","Leaf"],"rasa":["Tikta","Kashaya"],"guna":["Laghu","Ruksha","Sara"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Pitta","classicalUses":["Jwaraghna","Kusthaghna","Vranaropana","Krimighna"],"evidence":"Moderate","evidenceNote":"Echitamine and related alkaloids show antipyretic, antimicrobial, and antiplasmodial activity.","formulations":["Saptaparna Ghrita","Kutajashtaka"],"source":"Charaka Samhita, Sutrasthana 4","precautions":"Bark is toxic in overdose; use standardized extracts only.","emoji":"\ud83c\udf33","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/Alstonia_scholaris.jpg/640px-Alstonia_scholaris.jpg","category":"fever"},
