  {"id":"bilwa","name":"Bilwa (Bael)","sanskrit":"\u092c\u093f\u0932\u094d\u0935","alsoKnownAs":["Shriphala","Maloora"],"botanical":"Aegle marmelos","family":"Rutaceae","partsUsed":["Root","Fruit","Leaf"],"rasa":["Kashaya","Tikta"],"guna":["Laghu","Ruksha"],"virya":"Ushna","vipaka":"Katu","dosha":"Balances Kapha & Pitta (root); fruit is more Vata-pitta shamaka","classicalUses":["Atisara-ghna (ripe fruit)","Sangrahi (unripe fruit)","Deepana","Jwaraghna"],"evidence":"Strong","evidenceNote":"Marmelosin and tannins show antidysenteric, antidiarrheal, and antidiabetic activity.","formulations":["Bilwadi Churna","Bilwadi Gutika","Bijayasar"],"source":"Charaka Samhita, Sutrasthana 4","precautions":"Unripe fruit can constipate; ripe fruit can loosen.","emoji":"\ud83c\udf50","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Aegle_marmelos.jpg/640px-Aegle_marmelos.jpg","category":"digestive"},
